root.js-content:
stp.writeLog("Start: Time Out Notification");
stp.setAutoProcess(true);
stp.setUserId("CSBANK");
sRptId = stp.getXslMsgTagVal("message/Document/TmOutNtfctn/NtfctnId","Id");
sTxId = stp.getXslMsgTagVal("message/Document/TmOutNtfctn/TxId","Id");
stp.writeLog("sRptId=========="+sRptId);
stp.writeLog("sTxId=========="+sTxId);
var arrKeys = [["TSU_TID",sTxId]];
var arrGetDataResult = stp.SYS_getCUBKVal("GetBksInforByTxIdforTmOut",arrKeys);
var sIndex = sRptId.indexOf("-");
var sBIC = sRptId.substr(0,sIndex);
stp.writeLog("sBIC=========="+sBIC);
var sBuyrBkBIC = arrGetDataResult[0];
stp.writeLog("sBuyrBkBIC=========="+sBuyrBkBIC);
var sSellrBkBIC = arrGetDataResult[2];
stp.writeLog("sSellrBkBIC=========="+sSellrBkBIC);
var sBuyrNm = arrGetDataResult[3];
stp.writeLog("sBuyrNm=========="+sBuyrNm);
var sSellrNm = arrGetDataResult[1];
stp.writeLog("sSellrNm=========="+sSellrNm);
var sUnitNm = "";
if (sBIC == sBuyrBkBIC){
sUnitNm = sBuyrNm;
} else{
sUnitNm = sSellrNm;
}
var arrKeys1 = [["C_UNIT_NAME",sUnitNm]];
var arrGetDataResult1 = stp.SYS_getCUBKVal("GetUnitCodeByNm",arrKeys1);
var sUnitCode = arrGetDataResult1[0];
stp.writeLog("sUnitCode=========="+sUnitCode);
stp.setCmpId(sUnitCode);

var arrGetDataResult2 = stp.SYS_getCUBKVal("GetMainRefByTxId",arrKeys);
var sMainRef = arrGetDataResult2[0];
stp.setMainRef(sMainRef);
stp.updateFieldValue("PARENT_MAIN_REF",sTxId);
stp.updateFieldValue("CURRNT_STATUS","Time Out Notification");
stp.writeLog("End: Time Out Notification");
